function contaOcorrencias(str, ch) {
  let c = 0;
  for (let i = 0; i < str.length; i++) {
    if (str[i] === ch) c++;
  }
  return c;
}

function selectionSort(arr) {
  const a = arr.slice(); // não mutar o original
  for (let i = 0; i < a.length - 1; i++) {
    let min = i;
    for (let j = i + 1; j < a.length; j++) {
      if (a[j] < a[min]) min = j;
    }
    if (min !== i) {
      const tmp = a[i]; a[i] = a[min]; a[min] = tmp;
    }
  }
  return a;
}

function buscaBinaria(arr, alvo) {
  let ini = 0, fim = arr.length - 1;
  while (ini <= fim) {
    const meio = Math.floor((ini + fim) / 2);
    if (arr[meio] === alvo) return meio;
    if (arr[meio] < alvo) ini = meio + 1; else fim = meio - 1;
  }
  return -1;
}

function ehPalindromo(str) {
  const norm = (str || "").toLowerCase().replace(/[^a-z0-9]/g, "");
  for (let i = 0, j = norm.length - 1; i < j; i++, j--) {
    if (norm[i] !== norm[j]) return false;
  }
  return true;
}

function compressaoRLE(str) {
  if (!str) return "";
  let out = "";
  let cnt = 1;
  for (let i = 1; i <= str.length; i++) {
    if (i < str.length && str[i] === str[i-1]) {
      cnt++;
    } else {
      out += str[i-1] + String(cnt);
      cnt = 1;
    }
  }
  return out;
}
